//
// Package parsunart is the runtime shared by every Go parser generated by
// parsuna.
//
// A generated grammar package supplies its own TokenKind / RuleKind types
// (as uint16 aliases), a MatcherFunc, a skip-kind predicate, and a Step
// callback that runs one state body of the dispatch. Everything else —
// lexing, lookahead, skip routing, error recovery — lives here.
package parsunart

import (
	"fmt"
	"io"
	"unicode/utf8"
)

// Pos is a source position: byte offset plus 1-based line/column.
type Pos struct {
	Offset uint32
	Line   uint32
	Column uint32
}

// Span is a half-open range [Start, End) over the source.
type Span struct {
	Start, End Pos
}

// PointSpan is a zero-width span at a single point.
func PointSpan(p Pos) Span { return Span{Start: p, End: p} }

// Token is a lexed token: kind, source span, and the matched text.
//
// Kind is stored as uint16 to match the generated TokenKind enum's values.
// EOF is always 0 (EofKind); grammar tokens have ids starting at 1; the
// lexer emits ErrorKind (0xFFFF) when no DFA pattern matched at the
// current position. The parser runtime turns those into a paired
// EvError+EvGarbage sequence at pump time and never lets them reach
// generated dispatch (see Parser.Next).
type Token struct {
	Kind uint16
	Span Span
	Text string
}

// EofKind is the token-kind id reserved for end-of-input. Always 0.
const EofKind uint16 = 0

// ErrorKind is the token-kind sentinel emitted when the lexer can't match
// any pattern at the current position. Distinct from any grammar token id
// (0..0xFFFE), so dispatch arms naturally fall through to the recovery
// path.
const ErrorKind uint16 = 0xFFFF

// ParseError is a recoverable parse or lex error with its source span.
type ParseError struct {
	Message string
	Span    Span
}

// String formats the error as `error[line:col]: message`.
func (d ParseError) String() string {
	s, e := d.Span.Start, d.Span.End
	if s == e {
		return fmt.Sprintf("error[%d:%d]: %s", s.Line, s.Column, d.Message)
	}
	return fmt.Sprintf("error[%d:%d-%d:%d]: %s", s.Line, s.Column, e.Line, e.Column, d.Message)
}

// EventTag discriminates Event payload fields.
type EventTag uint8

const (
	EvEnter EventTag = iota
	EvExit
	EvToken
	// EvGarbage is a token consumed during error recovery — emitted
	// between an EvError and the recovery's sync point. Distinct from
	// EvToken so consumers can drop these from their AST or render
	// them as error spans without tracking recovery state externally.
	EvGarbage
	EvError
)

// Event is a single pull-parser event. Tag is one of the EV_* constants;
// the matching payload field (Rule, Token, Err) carries the data.
type Event struct {
	Tag   EventTag
	Rule  uint16
	Pos   Pos
	Token Token
	Err   ParseError
}

// Terminated is the sentinel state that means "parser finished".
const Terminated = -1

// MatcherFunc is the grammar-specific compiled DFA the runtime drives.
// It scans buf[start:] for the longest matching token in mode. Returns
// (bestLen, bestKind, scanned):
//   - bestLen: bytes consumed by the longest match (0 means no accept).
//   - bestKind: token kind of the longest match, or ErrorKind when no
//     accept state was reached.
//   - scanned: total bytes walked past start; equals len(buf)-start when
//     the scan stopped at end of input rather than a dead transition. The
//     streaming lexer uses this to detect buffer exhaustion mid-token.
//
// mode is the active lexer mode id — 0 for the default (anonymous) mode,
// further ids correspond to @mode(name) pre-annotations in declaration
// order. Generated matchers branch on it and dispatch into the per-mode
// state machine; grammars without modes ignore it.
type MatcherFunc func(buf []byte, start int, mode uint32) (int, uint16, int)

const lexChunk = 16384

// Lexer is a streaming DFA-driven lexer over an io.Reader. The grammar-
// specific DFA is supplied as a MatcherFunc.
type Lexer struct {
	reader    io.Reader
	buf       []byte
	bufPos    int
	eof       bool
	offset    uint32
	line, col uint32
	matcher   MatcherFunc
	// modeStack tracks the active lexer mode. Top of stack is what
	// NextToken passes to matcher. Initialised with the default mode
	// (id 0) and never empty; PopMode is a no-op past the bottom so a
	// stray `-> pop` action can't underflow.
	modeStack []uint32
}

// NewLexer builds a lexer over r.
func NewLexer(r io.Reader, matcher MatcherFunc) *Lexer {
	return &Lexer{reader: r, line: 1, col: 1, matcher: matcher, modeStack: []uint32{0}}
}

// PushMode pushes mode onto the mode stack; subsequent NextToken calls
// scan with that mode's DFA until a matching PopMode.
func (l *Lexer) PushMode(mode uint32) {
	l.modeStack = append(l.modeStack, mode)
}

// PopMode pops the topmost mode off the stack, leaving at least the
// default mode in place. Underflow is silently ignored.
func (l *Lexer) PopMode() {
	if len(l.modeStack) > 1 {
		l.modeStack = l.modeStack[:len(l.modeStack)-1]
	}
}

func (l *Lexer) pos() Pos { return Pos{Offset: l.offset, Line: l.line, Column: l.col} }

func (l *Lexer) readMore() bool {
	if l.eof {
		return false
	}
	if cap(l.buf)-len(l.buf) < lexChunk {
		newCap := cap(l.buf) * 2
		if newCap < len(l.buf)+lexChunk {
			newCap = len(l.buf) + lexChunk*2
		}
		nb := make([]byte, len(l.buf), newCap)
		copy(nb, l.buf)
		l.buf = nb
	}
	n, err := l.reader.Read(l.buf[len(l.buf) : len(l.buf)+lexChunk])
	if n > 0 {
		l.buf = l.buf[:len(l.buf)+n]
	}
	if err != nil || n == 0 {
		l.eof = true
		return n > 0
	}
	return true
}

func (l *Lexer) ensure(want int) {
	for !l.eof && len(l.buf)-l.bufPos < want {
		if !l.readMore() {
			break
		}
	}
}

// advance bumps position. Fast-path for pure ASCII non-newline slices,
// byte-by-byte walk otherwise so lines/columns track multi-byte UTF-8.
func (l *Lexer) advance(n int) {
	end := l.bufPos + n

	needsWalk := false
	for i := l.bufPos; i < end; i++ {
		b := l.buf[i]
		if b == '\n' || b >= 0x80 {
			needsWalk = true
			break
		}
	}
	if !needsWalk {
		l.col += uint32(n)
		l.offset += uint32(n)
		l.bufPos = end
	} else {
		for l.bufPos < end {
			b := l.buf[l.bufPos]
			l.bufPos++
			l.offset++
			if b == '\n' {
				l.line++
				l.col = 1
			} else if (b & 0xC0) != 0x80 {
				l.col++
			}
		}
	}
	if l.bufPos > 65536 {
		copy(l.buf, l.buf[l.bufPos:])
		l.buf = l.buf[:len(l.buf)-l.bufPos]
		l.bufPos = 0
	}
}

func (l *Lexer) longestMatch() (int, uint16) {
	mode := l.modeStack[len(l.modeStack)-1]
	for {
		bestLen, bestKind, scanned := l.matcher(l.buf, l.bufPos, mode)
		viewLen := len(l.buf) - l.bufPos
		if !l.eof && scanned == viewLen {
			if l.readMore() {
				continue
			}
		}
		return bestLen, bestKind
	}
}

// NextToken produces the next token. Emits repeated EOF once input ends.
// Lex failures come through with Kind == ErrorKind (0xFFFF).
func (l *Lexer) NextToken() Token {
	l.ensure(lexChunk)
	if len(l.buf)-l.bufPos == 0 {
		p := l.pos()
		return Token{Kind: EofKind, Span: PointSpan(p)}
	}
	bestLen, bestKind := l.longestMatch()
	start := l.pos()
	if bestLen == 0 {
		_, n := utf8.DecodeRune(l.buf[l.bufPos:])
		if n < 1 {
			n = 1
		}
		text := string(l.buf[l.bufPos : l.bufPos+n])
		l.advance(n)
		return Token{Kind: ErrorKind, Span: Span{Start: start, End: l.pos()}, Text: text}
	}
	text := string(l.buf[l.bufPos : l.bufPos+bestLen])
	l.advance(bestLen)
	return Token{Kind: bestKind, Span: Span{Start: start, End: l.pos()}, Text: text}
}

// Config is the grammar-specific callback bundle a generated parser wires
// into the runtime.
type Config struct {
	K      int
	IsSkip func(kind uint16) bool
	// Step runs one state body of the generated dispatch. Returns
	// the event that body produced (with `ok = true`) or a zero
	// Event and `ok = false` if the body was a pure transition step
	// — the runtime's Next loop calls Step again in that case.
	//
	// Step receives a *Cursor — a thin wrapper that exposes just the
	// runtime hooks generated dispatch needs (Look/State/PushRet/
	// Enter/Exit/etc.). Outside callers only see *Parser, which has
	// no such methods, so the parser's internal state stays sealed.
	Step func(c *Cursor) (Event, bool)
	// ApplyActions fires the per-token mode-stack actions declared
	// via `-> push(name)` / `-> pop`. Called once per lex token before
	// the skip / lookahead decision; nil is treated as a no-op for
	// grammars that declare no modes.
	ApplyActions func(kind uint16, lex *Lexer)
}

// Options controls runtime behaviour the caller picks per parser
// construction. Today this is just the skip-emission knob; future
// runtime-level toggles can extend the struct without breaking
// existing call sites because of zero-value defaults.
type Options struct {
	// DropSkips suppresses skip tokens at the source: the lexer still
	// matches them (they delimit structural tokens), but the parser's
	// Next loop never returns them. Default false (= emit skip tokens
	// as EvToken events, matching the historic behaviour).
	DropSkips bool
}

// recovery is in-flight error recovery. Set by TryConsume's mismatch
// path and RecoverTo; cleared once the lookahead lands on a sync token
// (or EOF). Each call to Next in recovery mode yields one Garbage
// event before re-checking the sync set.
type recovery struct {
	// sync is the set of token kinds to recover *to*. Recovery
	// consumes garbage until the lookahead matches one of these (or
	// EOF).
	sync []uint16
	// expected is set when recovery was triggered by a TryConsume for
	// a specific kind. expectedSet distinguishes "no expected kind"
	// from "expected kind 0 (EOF)".
	expected    uint16
	expectedSet bool
}

// Parser is the pull-based parser. Obtain one via NewParser, then call
// Next in a loop.
//
// Each Next call fires one of three modes — pump (refill lookahead,
// possibly yielding a skip), recovery (one Garbage / synced-Token event
// per call), or drive (one Step call) — and yields one event per mode.
// Step may return ok=false for pure-transition state bodies; the runtime
// simply loops drive again.
//
// Parser's only exported method is Next. The runtime hooks that
// generated dispatch calls into (Look/State/PushRet/Enter/Exit/etc.)
// live on *Cursor, which can only be constructed from inside the pull
// loop, so external callers can't poke at parser internals out of band.
type Parser struct {
	lex *Lexer
	// look is the lookahead ring, length K. Empty slots are awaiting
	// refill via pump-mode in Next. Empty slots are always a
	// contiguous suffix — Consume parks the new empty slot at index
	// K-1 and pump fills the leftmost empty.
	look       []Token
	lookFilled []bool
	prevEnd    Pos
	state      int
	ret        []int
	rec        recovery
	recActive  bool
	// pendingLexGarbage holds the lex-failure token (Kind = ErrorKind)
	// whose paired EvError the previous Next call returned; this call
	// owes the matching EvGarbage. Lex-failure tokens never enter
	// `look`, so dispatch reads `Look(i).Kind` as a real grammar token
	// id without an ErrorKind guard, and a stray bad byte doesn't push
	// the parser out of an active Star into SYNC recovery.
	pendingLexGarbage    Token
	pendingLexGarbageSet bool
	cfg                  Config
	opts                 Options
}

// NewParser builds a parser starting at state `entry`.
//
// All K lookahead slots start empty; the first call to Next enters
// pump-mode and primes them, so any leading skip tokens (e.g. whitespace
// before the first structural token) are emitted before the entry rule's
// Enter event.
func NewParser(lex *Lexer, entry int, cfg Config) *Parser {
	return NewParserWithOptions(lex, entry, cfg, Options{})
}

// NewParserWithOptions is NewParser plus runtime [Options] (today: a skip-
// drop toggle). Passing the zero-value Options is equivalent to
// NewParser.
func NewParserWithOptions(lex *Lexer, entry int, cfg Config, opts Options) *Parser {
	return &Parser{
		lex:        lex,
		state:      entry,
		cfg:        cfg,
		opts:       opts,
		look:       make([]Token, cfg.K),
		lookFilled: make([]bool, cfg.K),
	}
}

// takeToken pops the current lookahead token and shifts the buffer up
// by one. Slot K-1 is left empty so pump-mode can refill it before the
// next Step reads lookahead. Internal — callers wrap the result in
// the appropriate event tag.
func (p *Parser) takeToken() Token {
	t := p.look[0]
	p.prevEnd = t.Span.End
	for i := 0; i < p.cfg.K-1; i++ {
		p.look[i] = p.look[i+1]
		p.lookFilled[i] = p.lookFilled[i+1]
	}
	p.look[p.cfg.K-1] = Token{}
	p.lookFilled[p.cfg.K-1] = false
	return t
}

func (p *Parser) consume() Event {
	return Event{Tag: EvToken, Token: p.takeToken()}
}

func (p *Parser) errorHere(msg string) Event {
	return Event{Tag: EvError, Err: ParseError{Message: msg, Span: p.look[0].Span}}
}

func (p *Parser) armRecovery(sync []uint16, expected uint16, expectedSet bool) {
	p.rec = recovery{sync: sync, expected: expected, expectedSet: expectedSet}
	p.recActive = true
}

func containsKind(set []uint16, k uint16) bool {
	for _, x := range set {
		if x == k {
			return true
		}
	}
	return false
}

// Cursor is the handle that generated Step bodies talk to the runtime
// through. It's defined as `type Cursor Parser` — same memory layout,
// same fields, no extra pointer hop. Methods on *Cursor access the
// parser's state directly through `c.field`. The wrapper exists only
// as a *type-level* fence: it exposes the operations dispatch needs
// (lookahead access, return stack pushes, event builders, recovery
// arming), and external code can't get a *Cursor out of NewParser
// (the cast is internal to Next), so the parser's internal state
// stays sealed.
type Cursor Parser

// Look peeks at the i-th lookahead token. Generated Step only runs
// after pump-mode has filled every slot, so callers can read any slot
// unconditionally.
func (c *Cursor) Look(i int) Token { return c.look[i] }

// State returns the current state id.
func (c *Cursor) State() int { return c.state }

// SetState overwrites the current state id.
func (c *Cursor) SetState(s int) { c.state = s }

// PushRet pushes a return address onto the call stack.
func (c *Cursor) PushRet(s int) { c.ret = append(c.ret, s) }

// PopRet pops the top return address, or Terminated when the stack is empty.
func (c *Cursor) PopRet() int {
	if len(c.ret) == 0 {
		return Terminated
	}
	s := c.ret[len(c.ret)-1]
	c.ret = c.ret[:len(c.ret)-1]
	return s
}

// MatchesFirst reports whether the current lookahead matches any prefix
// in set. Used by generated dispatch logic with k > 1 lookahead.
func (c *Cursor) MatchesFirst(set [][]uint16) bool {
outer:
	for _, seq := range set {
		for i, want := range seq {
			if c.look[i].Kind != want {
				continue outer
			}
		}
		return true
	}
	return false
}

// Enter builds an Enter event for `rule` and returns it. Records the
// rule's start position as prevEnd so a later Exit without any
// intervening tokens still produces a zero-width span at the expected
// place.
func (c *Cursor) Enter(rule uint16) Event {
	pos := c.look[0].Span.Start
	c.prevEnd = pos
	return Event{Tag: EvEnter, Rule: rule, Pos: pos}
}

// Exit builds an Exit event for `rule`, anchored at the end of the
// previously consumed token (or the rule's start for empty rules).
func (c *Cursor) Exit(rule uint16) Event {
	return Event{Tag: EvExit, Rule: rule, Pos: c.prevEnd}
}

// Consume consumes the current lookahead and returns it as a Token
// event. Used on TryConsume's success path and on recovery's
// "synced-to-expected" path — both yield legitimate parse data.
func (c *Cursor) Consume() Event { return (*Parser)(c).consume() }

// TryConsume tries to consume a token of `kind`. On a hit returns a
// Token event. On a miss returns an Error event and arms recovery —
// subsequent Next calls skip Garbage one token at a time until
// the lookahead lands on `sync` (when it does, the matching token
// comes through as a normal Token event).
func (c *Cursor) TryConsume(kind uint16, sync []uint16, name string) Event {
	p := (*Parser)(c)
	if c.look[0].Kind == kind {
		return p.consume()
	}
	ev := p.errorHere("expected " + name)
	p.armRecovery(sync, kind, true)
	return ev
}

// RecoverTo arms recovery without an expected kind. Called from the
// dispatch error leaf: the caller has already arranged the
// post-recovery state and the returned Error event makes Step yield
// so recovery-mode can take over.
func (c *Cursor) RecoverTo(sync []uint16) { (*Parser)(c).armRecovery(sync, 0, false) }

// ErrorHere returns a recoverable error event at the current lookahead.
func (c *Cursor) ErrorHere(msg string) Event { return (*Parser)(c).errorHere(msg) }

// Next returns the next parse event and true, or a zero Event and
// false once input is fully consumed. This is the iterator-style
// `Next() (T, bool)` Go convention; there's no separate Next
// method.
//
// The loop runs three modes — pump, recovery, drive — each yielding at
// most one event per iteration before the loop runs again.
func (p *Parser) Next() (Event, bool) {
	for {
		// Pump-time-deferred Garbage half of a lex-failure pair: the
		// previous call returned the paired EvError; this call returns
		// the EvGarbage carrying the bad codepoint.
		if p.pendingLexGarbageSet {
			t := p.pendingLexGarbage
			p.pendingLexGarbage = Token{}
			p.pendingLexGarbageSet = false
			return Event{Tag: EvGarbage, Token: t}, true
		}

		// Pump mode: refill any empty lookahead slot. Slots fill
		// leftmost-first and Consume parks new empties at K-1, so
		// checking slot K-1 is the O(1) form of "any slot empty".
		if !p.lookFilled[p.cfg.K-1] {
			t := p.lex.NextToken()
			if p.cfg.ApplyActions != nil {
				p.cfg.ApplyActions(t.Kind, p.lex)
			}
			// Lex pattern miss — surface as a paired error+garbage so
			// the bad codepoint never enters lookahead. Keeps dispatch
			// honest (it never has to match against ErrorKind) and
			// stops a stray bad byte from pushing the parser out of
			// an active Star into SYNC recovery.
			if t.Kind == ErrorKind {
				p.pendingLexGarbage = t
				p.pendingLexGarbageSet = true
				return Event{Tag: EvError, Err: ParseError{Message: "unexpected character", Span: t.Span}}, true
			}
			if p.cfg.IsSkip(t.Kind) {
				if !p.opts.DropSkips {
					return Event{Tag: EvToken, Token: t}, true
				}
				continue
			}
			for i, ok := range p.lookFilled {
				if !ok {
					p.look[i] = t
					p.lookFilled[i] = true
					break
				}
			}
			continue
		}

		// Recovery mode: advance one step. Yield a Garbage event
		// for an unexpected token, a Token event when the sync hit
		// on the kind we were expecting, or finalise without
		// consuming and loop. Lookahead is guaranteed to carry a
		// real grammar kind — pump strips lex failures before they
		// reach the buffer.
		if p.recActive {
			k := p.look[0].Kind
			synced := k == EofKind || containsKind(p.rec.sync, k)
			if synced {
				wasExpected := p.rec.expectedSet && p.rec.expected == k
				p.recActive = false
				if wasExpected {
					return p.consume(), true
				}
				continue
			}
			return Event{Tag: EvGarbage, Token: p.takeToken()}, true
		}

		// EOF gate. On the first visit with trailing input, raise an
		// error and arm an empty-sync recovery so the rest of the
		// input drains as Garbage events one per call. Once recovery
		// has eaten its way to EOF the lookahead pins at EOF (the
		// lexer keeps yielding it), so this is naturally idempotent —
		// subsequent visits just return ok=false.
		if p.state == Terminated {
			if p.look[0].Kind == EofKind {
				return Event{}, false
			}
			ev := p.errorHere("expected end of input")
			p.armRecovery(nil, 0, false)
			return ev, true
		}

		// Drive mode: run one state body. If Step emitted, yield
		// it. Otherwise it just transitioned `cur` (and possibly
		// the return stack); loop and run the next body.
		// `(*Cursor)(p)` is a free cast — Cursor is `type Cursor
		// Parser` so the layouts are identical.
		if ev, ok := p.cfg.Step((*Cursor)(p)); ok {
			return ev, true
		}
	}
}
